+func extractRCHInnerCommand(command string) (string, bool) {
+	trimmed := strings.TrimSpace(command)
+	if trimmed == "" {
+		return "", false
+	}
+	fields := strings.Fields(trimmed)
+	if len(fields) < 2 {
+		return "", false
+	}
+	if fields[0] != "rch" {
+		return "", false
+	}
+
+	sep := -1
+	for i, field := range fields {
+		if field == "--" {
+			sep = i
+			break
+		}
+	}
+
+	if sep != -1 {
+		inner := fields[sep+1:]
+		if len(inner) == 0 {
+			return "", false
+		}
+		if len(fields) >= 3 && fields[1] == "build" && sep > 2 {
+			tool := fields[2]
+			if tool != "" && inner[0] != tool {
+				inner = append([]string{tool}, inner...)
+			}
+		}
+		return strings.Join(inner, " "), true
+	}
+
+	if len(fields) < 3 {
+		return "", false
+	}
+	switch fields[1] {
+	case "build":
+		inner := fields[2:]
+		if len(inner) == 0 {
+			return "", false
+		}
+		return strings.Join(inner, " "), true
+	case "intercept", "offload":
+		inner := fields[2:]
+		if len(inner) == 0 {
+			return "", false
+		}
+		return strings.Join(inner, " "), true
+	default:
+		return "", false
+	}
+}
